import type React from "react";
import { useState } from "react";
import { createPortal } from "react-dom";
import PopupLayer from "../components/PopupLayer";

export type SetupFormData = {
  name: string;
};

export interface SetupLayerProps {
  onComplete: (formData: SetupFormData) => void;
}

export const SetupLayer: React.FC<SetupLayerProps> = ({ onComplete }) => {
  const [name, setName] = useState("");
  const [error, setError] = useState<string | null>(null);

  const handleConfirm = () => {
    if (!name.trim()) {
      setError("닉네임을 입력해주세요!");
      return;
    }

    if (name.length < 2 || name.length > 10) {
      setError("닉네임은 2~10자 사이로 입력해주세요!");
      return;
    }

    if (document.activeElement instanceof HTMLElement) {
      document.activeElement.blur();
    }

    // 닉네임 유효성 검사 통과 시 완료 콜백 호출
    onComplete({
      name: name.trim(),
    });
  };

  const overlay = (
    <div className="fixed inset-0 z-[999] flex min-h-dvh items-center justify-center bg-black/50 p-4">
      <PopupLayer
        title="Spawn Monster!"
        content={
          <div className="flex flex-col items-center gap-4">
            <div className="w-full">
              <input
                type="text"
                value={name}
                onChange={(e) => {
                  setName(e.target.value);
                  setError(null);
                }}
                placeholder="Monster Name"
                maxLength={20}
                className="w-full px-3 py-2 text-center border-2 border-[#222] text-xs focus:outline-none focus:ring-2 focus:ring-[#d95763]"
              />
              <div className={"mt-4 text-xs text-gray-600"}>
                Name length: {name.length}/20
              </div>
              {error && (
                <p className="mt-4 text-component-negative text-[0.7em]">
                  {error}
                </p>
              )}
            </div>
          </div>
        }
        onConfirm={handleConfirm}
        confirmText="Start"
      />
    </div>
  );

  if (typeof document === "undefined") {
    return overlay;
  }

  return createPortal(overlay, document.body);
};
